<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'
import { ChevronRight, Download, Folder, TestTube, Trash2 } from 'lucide-vue-next'
import { api, errorMessage, type Connection } from '../api'
import { breadcrumbEntries } from '../cloud'
const connections = ref<Connection[]>([]); const selected = ref<Connection>(); const path = ref('/'); const breadcrumbs = computed(() => breadcrumbEntries(path.value)); const entries = ref<{ id: string; name: string; path: string; size: number; is_directory: boolean }[]>([]); const error = ref(''); const form = ref({ name: '', url: '', token: '', username: '', password: '' }); const offline = ref({ url: '', target: '/' }); const queued = ref('')
async function load() { try { connections.value = (await api.connections()).connections; error.value = '' } catch (e) { error.value = errorMessage(e) } }
async function save() { try { await api.saveConnection({ ...form.value, token: form.value.token || undefined, username: form.value.username || undefined, password: form.value.password || undefined }); form.value = { name: '', url: '', token: '', username: '', password: '' }; await load() } catch (e) { error.value = errorMessage(e) } }
async function browse(next = '/') { if (!selected.value) return; try { path.value = next; entries.value = (await api.listFolder(selected.value.id, next)).entries } catch (e) { error.value = errorMessage(e) } }
async function test(id: number) { try { await api.testConnection(id) } catch (e) { error.value = errorMessage(e) } }
async function remove(id: number) { try { await api.deleteConnection(id); if (selected.value?.id === id) selected.value = undefined; await load() } catch (e) { error.value = errorMessage(e) } }
async function submitOffline() { if (!selected.value) return; try { const result = await api.enqueueCloudAddOffline({ connection_id: selected.value.id, url: offline.value.url.trim(), target: offline.value.target.trim() }); queued.value = `Queued job ${result.job.id}`; offline.value.url = ''; error.value = '' } catch (e) { error.value = errorMessage(e) } }
function select(connection: Connection) { selected.value = connection; queued.value = ''; void browse('/') }
onMounted(load)
</script>
<template><div class="page-header"><div><p class="eyebrow">Saved credentials</p><h1>CloudDrive connections</h1><p class="page-subtitle">Credentials are stored by the local daemon and shown here only as presence flags.</p></div><button class="button secondary" type="button" @click="load">Refresh</button></div><p v-if="error" class="alert error">{{ error }}</p><section class="section-block"><div class="table-wrap"><table><thead><tr><th>Name</th><th>Endpoint</th><th>Credentials</th><th></th></tr></thead><tbody><tr v-for="connection in connections" :key="connection.id"><td>{{ connection.name }}</td><td class="error-cell">{{ connection.url }}</td><td>{{ connection.has_token ? 'Token set' : 'Login set' }}</td><td class="actions"><button class="icon-button" type="button" title="Browse folder" @click="select(connection)"><Folder :size="15" /></button><button class="icon-button" type="button" title="Test connection" @click="test(connection.id)"><TestTube :size="15" /></button><button class="icon-button danger-action" type="button" title="Delete connection" @click="remove(connection.id)"><Trash2 :size="15" /></button></td></tr><tr v-if="!connections.length"><td colspan="4" class="empty-cell">No connections.</td></tr></tbody></table></div></section><section class="section-block"><h2>Add connection</h2><form class="organize-form" @submit.prevent="save"><div class="form-grid"><label class="form-field"><span>Name</span><input v-model="form.name" required /></label><label class="form-field"><span>Endpoint</span><input v-model="form.url" type="url" required /></label><label class="form-field"><span>Token</span><input v-model="form.token" type="password" autocomplete="off" /></label><label class="form-field"><span>Username</span><input v-model="form.username" autocomplete="off" /></label><label class="form-field"><span>Password</span><input v-model="form.password" type="password" autocomplete="off" /></label></div><div class="form-actions"><button class="button primary">Save connection</button></div></form></section><section v-if="selected" class="section-block"><h2>Folder browser / {{ selected.name }}</h2><div class="breadcrumbs"><button type="button" @click="browse('/')">Root</button><template v-for="breadcrumb in breadcrumbs" :key="breadcrumb.path"><ChevronRight :size="15" /><button type="button" @click="browse(breadcrumb.path)">{{ breadcrumb.label }}</button></template></div><form class="organize-form" @submit.prevent="submitOffline"><div class="form-grid"><label class="form-field"><span>Offline URL</span><input v-model="offline.url" type="url" required /></label><label class="form-field"><span>Target folder</span><input v-model="offline.target" required /></label></div><div class="form-actions"><span v-if="queued" class="success-text">{{ queued }}</span><button class="button primary"><Download :size="15" />Queue URL</button></div></form><div class="table-wrap"><table><thead><tr><th>Name</th><th>Path</th><th>Type</th><th>Size</th></tr></thead><tbody><tr v-for="entry in entries" :key="entry.id"><td><button v-if="entry.is_directory" type="button" @click="browse(entry.path)">{{ entry.name }}</button><span v-else>{{ entry.name }}</span></td><td class="error-cell">{{ entry.path }}</td><td>{{ entry.is_directory ? 'Folder' : 'File' }}</td><td>{{ entry.size }}</td></tr><tr v-if="!entries.length"><td colspan="4" class="empty-cell">Folder is empty.</td></tr></tbody></table></div></section></template>
